CREATE OR REPLACE FUNCTION bump_data_freshness(p_domain_key text)
RETURNS void AS $$
BEGIN
  UPDATE data_freshness
     SET revision = revision + 1,
         changed_at = NOW()
   WHERE domain_key = p_domain_key;

  IF NOT FOUND THEN
    INSERT INTO data_freshness(domain_key, revision, changed_at)
    VALUES (p_domain_key, 1, NOW())
    ON CONFLICT (domain_key) DO NOTHING;
  END IF;
END;
$$ LANGUAGE plpgsql;
